import java.util.*;
import java.security.*;
import java.nio.charset.StandardCharsets;

/**
 * MAM (Mobile Application Management) Containerization System
 * Demonstrates secure separation of corporate and personal data on BYOD devices
 */
class MAMContainerSystem {

    // Container types for data isolation
    enum ContainerType {
        CORPORATE,
        PERSONAL,
        SHARED
    }

    // Security policy for containers
    static class ContainerPolicy {
        boolean encryptionRequired = true;
        boolean clipboardBlocked = false;
        boolean screenCaptureBlocked = true;
        boolean biometricRequired = false;
        boolean jailbreakDetectionEnabled = true;
        int maxFailedAttempts = 5;
        String allowedAppPackage = null;
        List<String> allowedDomains = new ArrayList<>();

        public void printPolicy() {
            System.out.println("=== Container Security Policy ===");
            System.out.println("Encryption Required: " + encryptionRequired);
            System.out.println("Clipboard Blocked: " + clipboardBlocked);
            System.out.println("Screen Capture Blocked: " + screenCaptureBlocked);
            System.out.println("Biometric Required: " + biometricRequired);
            System.out.println("Jailbreak Detection: " + jailbreakDetectionEnabled);
            System.out.println("Max Failed Attempts: " + maxFailedAttempts);
        }
    }

    // Data container for secure data storage
    static class SecureContainer {
        String containerId;
        ContainerType type;
        byte[] encryptionKey;
        Map<String, Object> dataStore;
        ContainerPolicy policy;
        boolean isLocked;
        int failedAttempts;
        Date createdAt;
        Date lastAccessed;

        public SecureContainer(String id, ContainerType type) {
            this.containerId = id;
            this.type = type;
            this.dataStore = new HashMap<>();
            this.policy = new ContainerPolicy();
            this.isLocked = true;
            this.failedAttempts = 0;
            this.createdAt = new Date();
            this.lastAccessed = createdAt;
            this.encryptionKey = generateEncryptionKey();
        }

        private byte[] generateEncryptionKey() {
            // Simplified key generation
            try {
                SecureRandom sr = new SecureRandom();
                byte[] key = new byte[32];
                sr.nextBytes(key);
                return key;
            } catch (Exception e) {
                return new byte[32];
            }
        }

        public boolean unlock(String credentials) {
            // Verify credentials and unlock container
            if (validateCredentials(credentials)) {
                isLocked = false;
                failedAttempts = 0;
                lastAccessed = new Date();
                System.out.println("[+] Container " + containerId + " unlocked successfully");
                return true;
            } else {
                failedAttempts++;
                System.out.println("[-] Failed unlock attempt. Attempts: " + failedAttempts);

                if (failedAttempts >= policy.maxFailedAttempts) {
                    lockContainer();
                    System.out.println("[-] Container locked due to max failed attempts");
                }
                return false;
            }
        }

        private boolean validateCredentials(String credentials) {
            // Simplified credential validation
            return credentials != null && credentials.length() >= 4;
        }

        public void lockContainer() {
            isLocked = true;
            System.out.println("[+] Container " + containerId + " locked");
        }

        public void storeData(String key, Object value) {
            if (!isLocked) {
                dataStore.put(key, value);
                lastAccessed = new Date();
                System.out.println("[+] Data stored in container " + containerId);
            } else {
                System.out.println("[-] Cannot store data - container is locked");
            }
        }

        public Object retrieveData(String key) {
            if (!isLocked) {
                lastAccessed = new Date();
                return dataStore.get(key);
            }
            return null;
        }
    }

    // Mobile Device with MAM support
    static class MobileDevice {
        String deviceId;
        String osType; // Android, iOS
        String osVersion;
        boolean isJailbroken;
        boolean isEncrypted;
        Map<ContainerType, SecureContainer> containers;

        public MobileDevice(String deviceId, String osType) {
            this.deviceId = deviceId;
            this.osType = osType;
            this.containers = new HashMap<>();
        }

        public boolean detectJailbreak() {
            // Jailbreak detection checks
            String[] jailbreakFiles = {
                "/Applications/Cydia.app",
                "/Library/MobileSubstrate/MobileSubstrate.dylib",
                "/bin/bash",
                "/usr/sbin/sshd",
                "/etc/apt"
            };

            // Simplified check - in real implementation would check actual files
            if (isJailbroken) {
                System.out.println("[-] WARNING: Jailbreak detected on device " + deviceId);
                return true;
            }
            return false;
        }

        public SecureContainer createContainer(ContainerType type) {
            String containerId = deviceId + "_" + type.name();
            SecureContainer container = new SecureContainer(containerId, type);
            containers.put(type, container);
            System.out.println("[+] Created " + type + " container on device " + deviceId);
            return container;
        }

        public SecureContainer getContainer(ContainerType type) {
            return containers.get(type);
        }
    }

    // MAM Administrator for enterprise management
    static class MAMAdministrator {
        private Map<String, MobileDevice> enrolledDevices;

        public MAMAdministrator() {
            this.enrolledDevices = new HashMap<>();
        }

        public void enrollDevice(MobileDevice device) {
            // Security checks before enrollment
            if (device.detectJailbreak()) {
                System.out.println("[-] Device enrollment blocked - jailbreak detected");
                return;
            }

            if (!device.isEncrypted) {
                System.out.println("[-] Warning: Device encryption not enabled");
            }

            enrolledDevices.put(device.deviceId, device);
            System.out.println("[+] Device " + device.deviceId + " enrolled in MAM");
        }

        public void applyCorporateContainer(MobileDevice device) {
            // Create corporate container with strict policies
            SecureContainer corpContainer = device.createContainer(ContainerType.CORPORATE);

            // Apply strict corporate policies
            corpContainer.policy.encryptionRequired = true;
            corpContainer.policy.biometricRequired = true;
            corpContainer.policy.screenCaptureBlocked = true;
            corpContainer.policy.clipboardBlocked = true;
            corpContainer.policy.jailbreakDetectionEnabled = true;
            corpContainer.policy.allowedDomains.add("*.corporate.com");

            System.out.println("[+] Corporate container policies applied");
            corpContainer.policy.printPolicy();
        }

        public void selectiveWipe(MobileDevice device) {
            // Selective wipe - only corporate data
            SecureContainer corpContainer = device.getContainer(ContainerType.CORPORATE);
            if (corpContainer != null) {
                corpContainer.dataStore.clear();
                System.out.println("[+] Corporate data wiped from device " + device.deviceId);
                System.out.println("[+] Personal data preserved");
            }
        }

        public void fullWipe(MobileDevice device) {
            // Full wipe - all containers
            device.containers.clear();
            System.out.println("[+] All data wiped from device " + device.deviceId);
        }

        public void revokeAccess(MobileDevice device) {
            // Revoke device access to corporate resources
            enrolledDevices.remove(device.deviceId);
            System.out.println("[+] Access revoked for device " + device.deviceId);
        }
    }

    public static void main(String[] args) {
        System.out.println("=== MAM Containerization Demo ===\n");

        MAMAdministrator admin = new MAMAdministrator();

        // Enroll a new device
        MobileDevice device = new MobileDevice("DEVICE_001", "Android");
        device.isEncrypted = true;
        device.isJailbroken = false;
        device.osVersion = "12.0";

        admin.enrollDevice(device);

        // Apply corporate container
        System.out.println("\n--- Applying Corporate Container ---");
        admin.applyCorporateContainer(device);

        // Access corporate container
        System.out.println("\n--- Accessing Corporate Data ---");
        SecureContainer corpContainer = device.getContainer(ContainerType.CORPORATE);
        corpContainer.unlock("secure_pin");
        corpContainer.storeData("cloud_credentials", "token_abc123");
        corpContainer.storeData("corporate_email", "employee@company.com");

        // Retrieve data
        String credentials = (String) corpContainer.retrieveData("cloud_credentials");
        System.out.println("Retrieved credentials: " + credentials);

        // Lock container
        corpContainer.lockContainer();

        // Attempt unauthorized access
        System.out.println("\n--- Attempting Unauthorized Access ---");
        corpContainer.unlock("wrong");
        corpContainer.unlock("wrong");
        corpContainer.unlock("wrong");
        corpContainer.unlock("wrong");
        corpContainer.unlock("wrong"); // Should lock after 5 attempts

        // Selective wipe when employee leaves
        System.out.println("\n--- Selective Wipe (Offboarding) ---");
        admin.selectiveWipe(device);
    }
}
